// Package quota implements a controller that enforces per-namespace limits on
// the number of CiliumNetworkPolicy resources, preventing policy sprawl in
// multi-tenant clusters.
package quota

import (
	"context"
	"fmt"
	"sync"

	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-quota-controller")

// PolicyQuotaController watches CiliumNetworkPolicy resources and enforces
// per-namespace limits on the number of policies.
type PolicyQuotaController struct {
	log    logrus.FieldLogger
	cnps   resource.Resource[*cilium_v2.CiliumNetworkPolicy]

	// maxPerNamespace is the maximum number of CiliumNetworkPolicy resources
	// allowed per namespace. Zero means no limit.
	maxPerNamespace int

	mu sync.RWMutex
	// namespacePolicies tracks the set of policy keys present in each namespace.
	// This allows accurate counting even when Upsert events are received for
	// already-known policies.
	namespacePolicies map[string]map[resource.Key]struct{}
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
//
// Parameters:
//   - log: structured logger for controller events.
//   - cnps: resource.Resource providing a stream of CiliumNetworkPolicy events.
//   - maxPerNamespace: maximum number of CiliumNetworkPolicy resources allowed
//     per namespace. A value of zero disables quota enforcement.
func NewPolicyQuotaController(
	log logrus.FieldLogger,
	cnps resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:               log,
		cnps:              cnps,
		maxPerNamespace:   maxPerNamespace,
		namespacePolicies: make(map[string]map[resource.Key]struct{}),
	}
}

// Run starts the controller loop and processes CiliumNetworkPolicy events until
// the provided context is cancelled.
func (c *PolicyQuotaController) Run(ctx context.Context) {
	c.log.Info("Starting PolicyQuotaController")

	cnpEvents := c.cnps.Events(ctx)

	for {
		select {
		case event, ok := <-cnpEvents:
			if !ok {
				c.log.Info("PolicyQuotaController stopping: event channel closed")
				return
			}
			c.handleEvent(event)
		case <-ctx.Done():
			c.log.Info("PolicyQuotaController stopping: context cancelled")
			return
		}
	}
}

// handleEvent processes a single CiliumNetworkPolicy resource event.
func (c *PolicyQuotaController) handleEvent(event resource.Event[*cilium_v2.CiliumNetworkPolicy]) {
	switch event.Kind {
	case resource.Sync:
		c.log.Debug("CiliumNetworkPolicy store synced")
		event.Done(nil)

	case resource.Upsert:
		ns := event.Object.Namespace
		key := event.Key

		c.mu.Lock()
		if _, exists := c.namespacePolicies[ns]; !exists {
			c.namespacePolicies[ns] = make(map[resource.Key]struct{})
		}
		c.namespacePolicies[ns][key] = struct{}{}
		count := len(c.namespacePolicies[ns])
		c.mu.Unlock()

		c.log.WithFields(logrus.Fields{
			logfields.K8sNamespace: ns,
			"count":                count,
			"maxPerNamespace":      c.maxPerNamespace,
		}).Debug("CiliumNetworkPolicy upserted")

		event.Done(nil)

	case resource.Delete:
		ns := event.Object.Namespace
		key := event.Key

		c.mu.Lock()
		if policies, exists := c.namespacePolicies[ns]; exists {
			delete(policies, key)
			if len(policies) == 0 {
				delete(c.namespacePolicies, ns)
			}
		}
		c.mu.Unlock()

		c.log.WithFields(logrus.Fields{
			logfields.K8sNamespace: ns,
		}).Debug("CiliumNetworkPolicy deleted")

		event.Done(nil)
	}
}

// CheckQuota returns an error if the namespace has reached or exceeded the
// maximum number of allowed CiliumNetworkPolicy resources. A nil error means
// the namespace is within quota.
//
// If maxPerNamespace is zero, quota enforcement is disabled and CheckQuota
// always returns nil.
func (c *PolicyQuotaController) CheckQuota(namespace string) error {
	if c.maxPerNamespace == 0 {
		return nil
	}

	c.mu.RLock()
	count := len(c.namespacePolicies[namespace])
	c.mu.RUnlock()

	if count >= c.maxPerNamespace {
		return fmt.Errorf(
			"namespace %q has reached the CiliumNetworkPolicy quota: %d/%d policies",
			namespace, count, c.maxPerNamespace,
		)
	}
	return nil
}

// NamespaceCount returns the current number of CiliumNetworkPolicy resources
// tracked in the given namespace.
func (c *PolicyQuotaController) NamespaceCount(namespace string) int {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return len(c.namespacePolicies[namespace])
}

