{"meta": null, "content": [{"type": "text", "text": "{"content":"1: // SPDX-License-Identifier: Apache-2.0\n2: // Copyright Authors of Cilium\n3: \n4: package resource\n5: \n6: import (\n7: \t\"k8s.io/apimachinery/pkg/api/meta\"\n8: \t\"k8s.io/client-go/tools/cache\"\n9: )\n10: \n11: // Key of an K8s object, e.g. name and optional namespace.\n12: type Key struct {\n13: \t// Name is the name of the object\n14: \tName string\n15: \n16: \t// Namespace is the namespace, or empty if object is not namespaced.\n17: \tNamespace string\n18: }\n19: \n20: func (k Key) String() string {\n21: \tif len(k.Namespace) \u003e 0 {\n22: \t\treturn k.Namespace + \"/\" + k.Name\n23: \t}\n24: \treturn k.Name\n25: }\n26: \n27: func NewKey(obj any) Key {\n28: \tif d, ok := obj.(cache.DeletedFinalStateUnknown); ok {\n29: \t\tnamespace, name, _ := cache.SplitMetaNamespaceKey(d.Key)\n30: \t\treturn Key{name, namespace}\n31: \t}\n32: \n33: \tmeta, err := meta.Accessor(obj)\n34: \tif err != nil {\n35: \t\treturn Key{}\n36: \t}\n37: \tif len(meta.GetNamespace()) \u003e 0 {\n38: \t\treturn Key{meta.GetName(), meta.GetNamespace()}\n39: \t}\n40: \treturn Key{meta.GetName(), \"\"}\n41: }\n42: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/cilium--v1.16.5@14bf8b70da6d30733726dd61ffc026d1ed2b187c/-/blob/pkg/k8s/resource/key.go"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: // SPDX-License-Identifier: Apache-2.0
