// TestNewPolicyQuotaController verifies that the constructor initialises the
// controller with the expected field values.
func TestNewPolicyQuotaController(t *testing.T) {
	mock := newMockResource()
	c := NewPolicyQuotaController(testLogger(), mock, 5)

	if c == nil {
		t.Fatal("expected non-nil controller")
	}
	if c.maxPerNamespace != 5 {
		t.Errorf("maxPerNamespace: got %d, want 5", c.maxPerNamespace)
