	mock := newMockResource()
	c := NewPolicyQuotaController(testLogger(), mock, 2)

	// Seed exactly maxPerNamespace policies.
	c.namespacePolicies["ns1"] = map[resource.Key]struct{}{
		makeKey("ns1", "p1"): {},
