	cancel()
	select {
	case <-done:
	case <-time.After(time.Second):
		t.Error("Run did not stop within 1 second after context cancellation")
	}
}

// TestRun_ChannelClose verifies that Run returns when the event channel is
// closed.
func TestRun_ChannelClose(t *testing.T) {
	mock := newMockResource()
	c := NewPolicyQuotaController(testLogger(), mock, 10)

	ctx := context.Background()

	done := make(chan struct{})
	go func() {
		defer close(done)
		c.Run(ctx)
	}()

	mock.close()

	select {
	case <-done:
	case <-time.After(time.Second):
		t.Error("Run did not stop within 1 second after channel close")
	}
}

// TestNamespaceCount verifies that NamespaceCount returns the correct count.
func TestNamespaceCount(t *testing.T) {
	mock := newMockResource()
	c := NewPolicyQuotaController(testLogger(), mock, 10)

	if count := c.NamespaceCount("ns1"); count != 0 {
		t.Errorf("expected 0 for unknown namespace, got %d", count)
	}

	c.namespacePolicies["ns1"] = map[resource.Key]struct{}{
		makeKey("ns1", "p1"): {},
		makeKey("ns1", "p2"): {},
		makeKey("ns1", "p3"): {},
	}

	if count := c.NamespaceCount("ns1"); count != 3 {
		t.Errorf("expected 3, got %d", count)
	}
}

